var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"또 고철 수집이군. 저번처럼 침식현상은 나타나지 않는 건가?","JPN":"また古鉄集めか。この前みたいに侵食現象が起きたりはしないのかな。","ENG":"Collecting scraps again? Do you think there will be another Counterside Effect like last time?","TWN":"又是收集廢鐵啊，這次不會像上次那樣出現侵蝕體吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDRE_DOLL_NPC_NULL","text":{"KOREA":"2종한테 다리가 뜯겨나갔던 녀석이 뭔 소리를 하는 거냐.","JPN":"第2種に足を千切られたやつが何を言っている。","ENG":"Is that what a guy who got his leg torn off by a Category 2 should be saying?","TWN":"被區區2類侵蝕體咬掉腿的傢伙在胡說些什麼呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ANDRE_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MILITIA_DOLL_NPC_NULL","text":{"KOREA":"팔다리가 뭐 하루 이틀 날라가는 것도 아니고…","JPN":"まあ手足がぶっ飛ぶのはいつものことだろう。","ENG":"We've been doing this long enough to get a limb torn off here and there...","TWN":"嘿嘿，缺條胳臂少條腿也不是什麼一天兩天事了……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"모두들 오늘도 열심히 해요!","JPN":"皆さん、今日も頑張りましょう！","ENG":"Let's work hard today, everyone!","TWN":"大家！今天也要加油喔！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마브카. 오늘은 민병단 분들과 함께 고물 수집을 하는 날이야.","JPN":"マブカ、今日は民兵団の皆さんと古鉄集めに行くの。","ENG":"Mavka, we collect junk with the militia today.","TWN":"瑪卡，今天是我們和民兵團一起收集破銅爛鐵的日子。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"쓸만해 보이는 물건이라면 전부 가져와 줘.","JPN":"使えそうなものならとりあえず全部持って来て。","ENG":"Bring back anything that seems useful.","TWN":"我們要把看起來有用的東西都帶回來。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"응… 알았어.","JPN":"うん、わかった。","ENG":"Okay.","TWN":"嗯……知道了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그리고 반드시 내 시야 안에서만 활동해야 해. 알았지?","JPN":"あと、必ず私の目が届く範囲内で動いてね。","ENG":"But you have to stay within my sight, okay?","TWN":"而且一定要在我的視線範圍內活動，知道嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"내가 못 보는 곳에서 또 고장나버리면 큰일이잖아.","JPN":"私の知らないところでまた動けなくなったら大変でしょう？","ENG":"Because it'll be a huge problem if you break down when I'm not there.","TWN":"如果在我看不到的地方又壞掉了，那可就糟了。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"어쩔 수 없지.","JPN":"仕方ないね。","ENG":"I can't complain about that.","TWN":"真是沒辦法。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그럼 이 주변만 돌아다닐게.","JPN":"じゃあこの辺で活動するよ。","ENG":"Then, I'll be patrolling around here.","TWN":"那我就在這附近轉轉吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"응응! 열심히 해줘~","JPN":"うんうん！　じゃあよろしくね！","ENG":"Okay! Then, see you later!","TWN":"嗯嗯！加油喔～"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사람이 살았던 흔적이 그대로 있어.","JPN":"人が暮らしていた痕跡が残っている。","ENG":"There are still traces of the people who used to live here.","TWN":"這裡還留有人生活的痕跡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내가 현역 시절부터 있었더라면….","JPN":"現役時代にここに来ていれば……","ENG":"If only I were here when I was still a part of the army...","TWN":"如果我在還沒被廢棄時就來的話……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"걱정할 것 없어. 이런 유배지로 발령받을 일은 없었을 테니까.","JPN":"そもそもこういう流刑地に派遣されることなんてなかったでしょう。","ENG":"No need to worry about that. Because then, you wouldn't be dispatched to a place of exile like here.","TWN":"不用擔心。不會被派到這種邊疆地帶的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"어제 안드레이를 만났다면서? 내 목소린 기억하고 있지?","JPN":"昨日アンドレイに会ったんだって？　私の声覚えてる？","ENG":"I heard you met with Andrei yesterday. You remember my voice, don't you?","TWN":"聽說你昨天見到安德烈了？還記得我的聲音嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"분명 민병단의 올가… 올가 언니라고 불러야 될까?","JPN":"民兵団のオルガ……　オルガさん、と呼べばいい？","ENG":"You're Olga from the militia... Or would you prefer if I called you Ms. Olga?","TWN":"你是民兵團的歐嘉……該叫你歐嘉姊姊嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"……그냥 올가라고 불러.","JPN":"……オルガでいいよ。","ENG":"...Just Olga is fine.","TWN":"……就叫歐嘉吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그때는 정신이 없어서 제대로 이야기도 못 나눴네.","JPN":"あの時はバタバタしてて、ちゃんとお話もできなかったわね。","ENG":"I don't believe we had a chance to talk that day because of everything going on.","TWN":"那時候情況緊急，沒能好好聊聊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"우리 마을이 텃세가 심하다는 건 많이 들었겠지?","JPN":"うちの村人たちは警戒心が強いって、聞いてるでしょう？","ENG":"I'm sure you already heard how territorial our village is, right?","TWN":"你應該也發現了，我們村子排外很嚴重吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"난 사람들과 원만히 지내고 싶어.","JPN":"私は他の人たちと穏便に過ごしたい。","ENG":"I want to get along with these people.","TWN":"我想和大家和睦相處。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"당연히 그렇겠지.","JPN":"誰でもそう思うでしょうね。","ENG":"Of course, you do.","TWN":"那是當然。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"한번 말해봐.","JPN":"感想を聞かせてもらえるかしら。","ENG":"Then, tell me.","TWN":"說說看吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"……이 장소를 와본 소감이 어때?","JPN":"……ここを見て、どう思った？","ENG":"...What is your impression of this place?","TWN":"……來了這裡以後感想如何？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……처참해.","JPN":"……凄惨だな、と。","ENG":"...It's devastating.","TWN":"……慘不忍睹。"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OLGA_DOLL_NPC_NULL","text":{"KOREA":"그뿐이야?","JPN":"それだけ？","ENG":"Is that all?","TWN":"就這樣嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"OLGA_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};